package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsCommentMarkerSet_WhenCommentMarkerIsNull() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        // Use reflection to set commentMarker to null
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);

        // Since commentMarker is final, remove final modifier via reflection
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(commentMarkerField, commentMarkerField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        commentMarkerField.set(csvFormat, null);

        assertFalse(csvFormat.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_WhenCommentMarkerIsSet() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        // Use reflection to set commentMarker to a non-null character
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);

        // Remove final modifier
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(commentMarkerField, commentMarkerField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        commentMarkerField.set(csvFormat, '#');

        assertTrue(csvFormat.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_WithWithCommentMarkerMethod() {
        CSVFormat csvFormat = CSVFormat.DEFAULT.withCommentMarker('#');
        assertTrue(csvFormat.isCommentMarkerSet());

        CSVFormat csvFormatNull = CSVFormat.DEFAULT.withCommentMarker((Character) null);
        assertFalse(csvFormatNull.isCommentMarkerSet());
    }
}
